// Generates resources/js/lib/iconBundle.ts — a minimal Iconify collection holding
// only the mdi: icons referenced in resources/js, so @iconify/react renders them
// from the bundle instead of fetching each from api.iconify.design at runtime
// (offline, faster, and no external connect-src). Run: `npm run icons:build`.
import mdi from '@iconify/json/json/mdi.json' with { type: 'json' };
import { readdirSync, readFileSync, writeFileSync, statSync } from 'node:fs';
import { join } from 'node:path';

const SRC = 'resources/js';
const OUT = 'resources/js/lib/iconBundle.ts';

/** Every .ts/.tsx source file under resources/js, excluding tests. */
function sourceFiles(dir) {
    return readdirSync(dir).flatMap((entry) => {
        const path = join(dir, entry);
        if (statSync(path).isDirectory()) return sourceFiles(path);
        if (!/\.tsx?$/.test(entry) || /\.test\./.test(entry)) return [];
        return [path];
    });
}

const used = new Set();
for (const file of sourceFiles(SRC)) {
    for (const m of readFileSync(file, 'utf8').matchAll(/mdi:[a-z0-9-]+/g)) {
        used.add(m[0].slice('mdi:'.length));
    }
}

const icons = {};
const aliases = {};
const missing = [];

/** Ensure `name` (a real icon or an alias chain) is present in the subset. */
function include(name) {
    if (icons[name] || aliases[name]) return true;
    if (mdi.icons[name]) {
        icons[name] = mdi.icons[name];
        return true;
    }
    if (mdi.aliases?.[name]) {
        aliases[name] = mdi.aliases[name];
        return include(mdi.aliases[name].parent);
    }
    return false;
}

for (const name of [...used].sort((a, b) => a.localeCompare(b))) {
    if (!include(name)) missing.push(name);
}

if (missing.length) {
    console.error(`Unknown mdi icons (typo, or renamed upstream):\n  ${missing.join('\n  ')}`);
    process.exit(1);
}

const bundle = { prefix: 'mdi', icons, aliases, width: mdi.width, height: mdi.height };
const banner =
    '// AUTO-GENERATED by scripts/build-icon-bundle.mjs — do not edit.\n' +
    '// Regenerate with `npm run icons:build` after adding or removing an mdi: icon.\n';
writeFileSync(
    OUT,
    `${banner}import type { IconifyJSON } from '@iconify/react';\n\nexport const mdiBundle = ${JSON.stringify(bundle)} as unknown as IconifyJSON;\n`,
);

console.log(`Wrote ${OUT}: ${Object.keys(icons).length} icons + ${Object.keys(aliases).length} aliases.`);
